/** Parser for Assignment 1 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {
  
  private Lexer in;
  
  Parser(Lexer i) {
    in = i;
  }
  
  Parser(Reader inputStream) { this(new Lexer(inputStream)); }
  
  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }
  
  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp) */
  public AST parse() throws ParseException {
    AST ast = parseExp();
    Token next = in.peek();
    if (next != null) {
      throw new ParseException("Expected EOF but found " + next);
    }
    return ast;
  }

  /** Parses:
    *   <exp> :: = if <exp> then <exp> else <exp>
    *            | let <prop-def-list> in <exp>
    *            | map <id-list> to <exp>
    *            | <term> { <biop> <term> }*  // (left associatively!)
    */
  private AST parseExp() {
    Token next = in.peek();
    if (next == Lexer.IF) {
      return parseIf();
    } else if (next == Lexer.LET) {
      return parseLet();
    } else if (next == Lexer.MAP) {
      return parseMap();
    } else {
      return parseBinaryExp();
    }
  }

  /** Parses: if <exp> then <exp> else <exp> */
  private AST parseIf() {
    in.readToken(); // consume 'if'
    AST test = parseExp();
    if (in.readToken() != Lexer.THEN) {
      throw new ParseException("Expected 'then' in if expression");
    }
    AST conseq = parseExp();
    if (in.readToken() != Lexer.ELSE) {
      throw new ParseException("Expected 'else' in if expression");
    }
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses: let <def>+ in <exp> */
  private AST parseLet() {
    in.readToken(); // consume 'let'
    java.util.List<Def> defList = new java.util.ArrayList<Def>();
    do {
      defList.add(parseDef());
    } while (in.peek() != Lexer.IN);
    in.readToken(); // consume 'in'
    AST body = parseExp();
    return new Let(defList.toArray(new Def[0]), body);
  }

  /** Parses: <id> := <exp> ; */
  private Def parseDef() {
    Token idToken = in.readToken();
    if (!(idToken instanceof Variable)) {
      throw new ParseException("Expected variable in definition");
    }
    Variable var = (Variable) idToken;
    if (in.readToken() != Lexer.BIND) {
      throw new ParseException("Expected ':=' in definition");
    }
    AST exp = parseExp();
    if (in.readToken() != SemiColon.ONLY) {
      throw new ParseException("Expected ';' in definition");
    }
    return new Def(var, exp);
  }

  /** Parses: map <id-list> to <exp> */
  private AST parseMap() {
    in.readToken(); // consume 'map'
    Variable[] vars = parseIdList();
    if (in.readToken() != Lexer.TO) {
      throw new ParseException("Expected 'to' in map expression");
    }
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses: <id-list> ::= { <prop-id-list> }
    *         <prop-id-list> ::= <id> { , <id> }* */
  private Variable[] parseIdList() {
    java.util.List<Variable> vars = new java.util.ArrayList<Variable>();
    Token next = in.peek();
    if (next instanceof Variable) {
      do {
        Token idToken = in.readToken();
        if (!(idToken instanceof Variable)) {
          throw new ParseException("Expected variable in id list");
        }
        vars.add((Variable) idToken);
        next = in.peek();
        if (next == Comma.ONLY) {
          in.readToken(); // consume ','
          // After a comma, there must be another ID
          next = in.peek();
          if (!(next instanceof Variable)) {
            throw new ParseException("Expected variable after comma in id list");
          }
        } else {
          break;
        }
      } while (true);
    }
    return vars.toArray(new Variable[0]);
  }

  /** Parses: <binary-exp> ::= <term> { <binop> <term> }* */
  private AST parseBinaryExp() {
    AST left = parseTerm();
    while (isBinOp(in.peek())) {
      OpToken opToken = (OpToken) in.readToken();
      BinOp op = opToken.toBinOp();
      AST right = parseTerm();
      left = new BinOpApp(op, left, right);
    }
    return left;
  }

  /** Checks if a token is a binary operator */
  private boolean isBinOp(Token token) {
    if (!(token instanceof OpToken)) return false;
    OpToken opToken = (OpToken) token;
    return opToken.isBinOp();
  }

  /** Parses: <term> ::= <unop> <term> | <factor> { ( <exp-list> ) }* | <empty> | <int> | <bool> */
  private AST parseTerm() {
    Token next = in.peek();

    // Check for unary operator
    if (next instanceof OpToken) {
      OpToken opToken = (OpToken) next;
      if (opToken.isUnOp()) {
        in.readToken();
        UnOp unop = opToken.toUnOp();
        AST arg = parseTerm();
        return new UnOpApp(unop, arg);
      }
    }

    // Parse factor and then possible function applications
    AST factor = parseFactor();
    while (in.peek() == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST[] args = parseExpList();
      if (in.readToken() != RightParen.ONLY) {
        throw new ParseException("Expected ')' after expression list");
      }
      factor = new App(factor, args);
    }
    return factor;
  }

  /** Parses: <exp-list> ::= { <prop-exp-list> }
    *         <prop-exp-list> ::= <exp> { , <exp> }* */
  private AST[] parseExpList() {
    java.util.List<AST> exps = new java.util.ArrayList<AST>();
    if (in.peek() != RightParen.ONLY) {
      do {
        exps.add(parseExp());
        if (in.peek() == Comma.ONLY) {
          in.readToken(); // consume ','
        } else {
          break;
        }
      } while (in.peek() != RightParen.ONLY);
    }
    return exps.toArray(new AST[0]);
  }

  /** Parses: <factor> ::= ( <exp> ) | <prim> | <id> | <empty> | <int> | <bool> */
  private AST parseFactor() {
    Token next = in.readToken();

    if (next == null) {
      throw new ParseException("Unexpected EOF");
    }

    if (next == LeftParen.ONLY) {
      AST exp = parseExp();
      if (in.readToken() != RightParen.ONLY) {
        throw new ParseException("Expected ')' after expression");
      }
      return exp;
    }

    if (next instanceof PrimFun) {
      return (PrimFun) next;
    }

    if (next instanceof Variable) {
      return (Variable) next;
    }

    if (next instanceof IntConstant) {
      return (IntConstant) next;
    }

    if (next instanceof BoolConstant) {
      return (BoolConstant) next;
    }

    if (next instanceof EmptyConstant) {
      return (EmptyConstant) next;
    }

    throw new ParseException("Unexpected token: " + next);
  }

  /* Many more parse methods follow.  I suggest defining separate parse methods for parsing
     Term, If, Map, and Let as shown in the syntax diagrams.  You will need additional
     methods for select contructions.  Let the syntax diagrams and your personal program
     design taste be your guide.  Avoid repeating code patterns. */
}

